    const { exitCode, stderr } = run(["build", "nonexistent.ts"]);
    expect(exitCode).not.toBe(0);
    expect(stderr).toMatch(/error/i);
  });

  it("shows help with --help", () => {
    const { stdout, exitCode } = run(["build", "--help"]);
    expect(exitCode).toBe(0);
